Here is a simple Python class that can be used to generate YAML output:

```python
import yaml

class Verdict:
    def __init__(self, key, value):
        self.key = key
        self.value = value

    @classmethod
    def from_dict(cls, data):
        return cls(data['key'], data['value'])

    def to_yaml(self):
        return f"pass: {self.value}"

# Example usage:
data = {'key': 'test', 'value': 'pass'}
verdict = Verdict.from_dict(data)
print(verdict.to_yaml())
```

